  "const startedAt = Date.now();\r\n\r\nexport interface HealthPayload {\r\n  readonly status: 'healthy';\r\n  readonly app: string;\r\n  readonly version: string;\r\n  readonly timestamp: string;\r\n  readonly uptime: number;\r\n}\r\n\r\nexport interface HealthRouteData {\r\n  readonly payload: HealthPayload;\r\n}\r\n\r\nexport function buildPayload(appName: string = '{{appName}}'): HealthPayload {\r\n  return {\r\n    status: 'healthy',\r\n    app: appName,\r\n    version: '0.0.0',\r\n    timestamp: new Date().toISOString(),\r\n    uptime: Math.floor((Date.now() - startedAt) / 1000),\r\n  };\r\n}\r\n\r\nexport function toHealthRouteData(value: unknown): HealthRouteData | undefined {\r\n  if (typeof value !== 'object' || value === null || !('payload' in value)) {\r\n    return undefined;\r\n  }\r\n\r\n  return value as HealthRouteData;\r\n}\r\n";
