  "import DesignCompositionView from './(_components)/composition-view.tsx';\r\nimport { appRoutes } from '@app/router.ts';\r\nimport { definePage } from '@app/utils.ts';\r\n\r\nexport const designCompositionPage = definePage()\r\n  .withRoute(appRoutes.designComposition)\r\n  .withMeta(() => ({\r\n    title: 'Composition rules — NetScript design system',\r\n    description: 'Layering, ownership, and composition rules for scaffolded fresh-ui surfaces.',\r\n  }))\r\n  .withLayer('composition', DesignCompositionView, () => ({}))\r\n  .withLayout((slots) => slots.composition())\r\n  .build();\r\n\r\nexport const { default: page } = designCompositionPage;\r\nexport { page as default };\r\n";
const template_019 =
  "import type { VNode } from 'preact';\r\nimport type { ComponentChildren } from 'preact';\r\nimport { Badge, Button } from '@app/components/ui/mod.ts';\r\n\r\nconst SECTIONS = [\r\n  { id: 'layers', label: 'Layers' },\r\n  { id: 'ownership', label: 'Ownership' },\r\n  { id: 'tokens', label: 'Tokens' },\r\n  { id: 'layout', label: 'Layout objects' },\r\n  { id: 'attributes', label: 'Attributes' },\r\n  { id: 'rules', label: 'Do / don’t' },\r\n] as const;\r\n\r\n/** Source: @netscript/fresh-ui L0 layer conventions (§Layer Rules). */\r\nconst LAYERS = [\r\n  {\r\n    id: 'L0',\r\n    name: 'Platform contract',\r\n    ownership: 'imported · package-owned',\r\n    rule:\r\n      'Token conventions, the data-part / data-state / ARIA rules, and the VisuallyHidden, SrOnly, and Show primitives. Platform elements stay the default — wrappers exist only where they encode behavior or an accessibility contract.',\r\n  },\r\n  {\r\n    id: 'L1',\r\n    name: 'Runtime behavior',\r\n    ownership: 'imported · package-owned',\r\n    rule:\r\n      'Interactive primitives (accordion, tabs, drawer, tooltip) that centralize keyboard interaction, focus management, and ARIA. L1 emits data attributes, refs, and handlers — never ns-* component classes.',\r\n  },\r\n  {\r\n    id: 'L2',\r\n    name: 'Registry components',\r\n    ownership: 'copied · app-owned',\r\n    rule:\r\n      'May import L0 or L1, and may emit ns-* classes where the class is the styling contract. An L2 item must not import another L2 item: shared behavior moves down to L0/L1, shared composition moves up to L3.',\r\n  },\r\n  {\r\n    id: 'L3',\r\n    name: 'Blocks',\r\n    ownership: 'copied · app-owned',\r\n    rule:\r\n      'Compose L2 items and application data seams into dashboard-scale arrangements — page headers, data tables, filter rails.',\r\n  },\r\n  {\r\n    id: 'L4',\r\n    name: 'Framework integration',\r\n    ownership: 'yours',\r\n    rule:\r\n      'Routes, island wiring, and data loading live in the application, outside @netscript/fresh-ui entirely.',\r\n  },\r\n] as const;\r\n\r\nconst DOS_AND_DONTS = [\r\n  {\r\n    doText: 'Compose new surfaces from Card, Panel, and the layout objects.',\r\n    dontText: 'Import one L2 component from another (button.tsx inside select.tsx).',\r\n  },\r\n  {\r\n    doText: 'Push behavior two components share down into L0/L1.',\r\n    dontText: 'Copy-paste keyboard or focus logic between L2 components.',\r\n  },\r\n  {\r\n    doText: 'Express state through semantic intents — Badge variant=’success’.',\r\n    dontText: 'Hardcode a raw color (#22c55e) because it “looks right” in one theme.',\r\n  },\r\n  {\r\n    doText: 'Reference var(--ns-primary) or a color-mix() of semantic tokens.',\r\n    dontText: 'Reference a primitive ramp step (--ns-copper-6) from component CSS.',\r\n  },\r\n  {\r\n    doText: 'Reach for native <select>, <dialog>, popover, and <details> first.',\r\n    dontText: 'Re-implement platform behavior with JavaScript state.',\r\n  },\r\n  {\r\n    doText: 'Edit your ui:add copies freely — after the copy, they are your code.',\r\n    dontText: 'Wait for a package update to change a copied component.',\r\n  },\r\n] as const;\r\n\r\nfunction SectionHeading(\r\n  { id, title, lede }: { id: string; title: string; lede: string },\r\n): VNode {\r\n  return (\r\n    <header class='ns-token-section__head'>\r\n      <h2 id={id} class='ns-token-section__title'>{title}</h2>\r\n      <p class='ns-token-section__lede'>{lede}</p>\r\n    </header>\r\n  );\r\n}\r\n\r\nfunction LayoutSpecimen(\r\n  { klass, note, children }: { klass: string; note: string; children: ComponentChildren },\r\n): VNode {\r\n  return (\r\n    <figure class='ns-rules-specimen'>\r\n      <figcaption class='ns-rules-specimen__cap'>\r\n        <code>{klass}</code>\r\n        <span>{note}</span>\r\n      </figcaption>\r\n      <div class='ns-rules-specimen__canvas'>{children}</div>\r\n    </figure>\r\n  );\r\n}\r\n\r\nfunction Plate({ children }: { children: ComponentChildren }): VNode {\r\n  return <div class='ns-rules-plate'>{children}</div>;\r\n}\r\n\r\nexport default function DesignCompositionView() {\r\n  return (\r\n    <main class='ns-tokens-page'>\r\n\r\n      <header class='ns-page-header'>\r\n        <div class='ns-cluster ns-cluster--md'>\r\n          <h1>Composition</h1>\r\n          <Badge variant='primary'>NS One</Badge>\r\n          <Badge variant='muted'>L0 contract</Badge>\r\n        </div>\r\n        <p class='ns-lede'>\r\n          How the pieces are allowed to fit together: the layer ladder, who owns which code, what\r\n          colors components may speak, and the layout vocabulary that holds pages together.\r\n        </p>\r\n      </header>\r\n\r\n      <div class='ns-tokens-layout'>\r\n        <nav class='ns-tokens-rail' aria-label='Composition sections'>\r\n          {SECTIONS.map((section) => (\r\n            <a key={section.id} href={`#${section.id}`} class='ns-tokens-rail__link'>\r\n              {section.label}\r\n            </a>\r\n          ))}\r\n        </nav>\r\n\r\n        <div class='ns-tokens-sections'>\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='layers'\r\n              title='The layer ladder'\r\n              lede='Five layers, one direction of dependency. Anything may import a layer below it; nothing imports sideways or up.'\r\n            />\r\n            <ol class='ns-rules-ladder'>\r\n              {LAYERS.map((layer) => (\r\n                <li key={layer.id} class='ns-rules-rung'>\r\n                  <div class='ns-rules-rung__head'>\r\n                    <span class='ns-rules-rung__id'>{layer.id}</span>\r\n                    <span class='ns-rules-rung__name'>{layer.name}</span>\r\n                    <span class='ns-rules-rung__own'>{layer.ownership}</span>\r\n                  </div>\r\n                  <p class='ns-rules-rung__rule'>{layer.rule}</p>\r\n                </li>\r\n              ))}\r\n            </ol>\r\n          </section>\r\n\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='ownership'\r\n              title='Two delivery models'\r\n              lede='The package draws a hard line between code it keeps and code it gives away.'\r\n            />\r\n            <div class='ns-rules-pair'>\r\n              <article class='ns-rules-model'>\r\n                <h3 class='ns-rules-model__title'>Imported surface</h3>\r\n                <p class='ns-rules-model__body'>\r\n                  The root entrypoint exports only the stable helpers safe to keep as runtime\r\n                  dependencies — <code>cn()</code> and the toast helpers — plus the{' '}\r\n                  <code>/primitives</code> (L0) and <code>/interactive</code>{' '}\r\n                  (L1) entry points. This code updates with the package.\r\n                </p>\r\n              </article>\r\n              <article class='ns-rules-model'>\r\n                <h3 class='ns-rules-model__title'>Copy-source registry</h3>\r\n                <p class='ns-rules-model__body'>\r\n                  Every component, block, island, style, and theme item is copy-source.{' '}\r\n                  <code>ui:add</code>{' '}\r\n                  writes it into your project and it becomes your code — deliberately, because UI\r\n                  needs project-specific customization that a stable package API cannot absorb.\r\n                  Package updates never touch a copy.\r\n                </p>\r\n              </article>\r\n            </div>\r\n          </section>\r\n\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='tokens'\r\n              title='The token rule'\r\n              lede='Components are theme-blind. NS One is the first theme, not the system.'\r\n            />\r\n            <ul class='ns-rules-list'>\r\n              <li>\r\n                Component CSS consumes the semantic <code>--ns-*</code> vocabulary and Tailwind{' '}\r\n                <code>*-ns-*</code> utilities — nothing else.\r\n              </li>\r\n              <li>\r\n                Derived shades come from <code>color-mix()</code>{' '}\r\n                over semantic tokens, so they re-derive under every theme.\r\n              </li>\r\n              <li>\r\n                Primitive ramp steps are theme raw material: a theme maps them onto roles, and\r\n                components never reference a ramp directly.\r\n              </li>\r\n              <li>\r\n                Raw color values are allowed only as documented platform fallbacks the vocabulary\r\n                cannot express.\r\n              </li>\r\n              <li>\r\n                A theme is a generated artifact set — <code>tokens.css</code>,{' '}\r\n                <code>theme-bridge.css</code>, <code>tokens.json</code>{' '}\r\n                — produced from a DTCG source. Swap the artifacts and every copied component\r\n                follows.\r\n              </li>\r\n            </ul>\r\n            <div class='ns-cluster'>\r\n              <Button type='link' href='/design/tokens' variant='outline' size='sm'>\r\n                Token vocabulary\r\n              </Button>\r\n              <Button type='link' href='/design/components' variant='outline' size='sm'>\r\n                Component gallery\r\n              </Button>\r\n            </div>\r\n          </section>\r\n\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='layout'\r\n              title='Layout objects'\r\n              lede='Theme-independent CSS objects from the layout-objects style item. Blocks and pages compose these instead of inventing one-off flex soup; gaps come from the spacing scale.'\r\n            />\r\n            <div class='ns-rules-specimens'>\r\n              <LayoutSpecimen klass='.ns-stack' note='vertical rhythm; gap via --ns-stack-gap'>\r\n                <div class='ns-stack ns-stack--sm'>\r\n                  <Plate>one</Plate>\r\n                  <Plate>two</Plate>\r\n                  <Plate>three</Plate>\r\n                </div>\r\n              </LayoutSpecimen>\r\n              <LayoutSpecimen klass='.ns-cluster' note='inline grouping that wraps'>\r\n                <div class='ns-cluster'>\r\n                  <Plate>alpha</Plate>\r\n                  <Plate>beta</Plate>\r\n                  <Plate>gamma</Plate>\r\n                  <Plate>delta</Plate>\r\n                  <Plate>epsilon</Plate>\r\n                </div>\r\n              </LayoutSpecimen>\r\n              <LayoutSpecimen klass='.ns-grid--3' note='fixed three-up grid'>\r\n                <div class='ns-grid ns-grid--3'>\r\n                  <Plate>1</Plate>\r\n                  <Plate>2</Plate>\r\n                  <Plate>3</Plate>\r\n                </div>\r\n              </LayoutSpecimen>\r\n              <LayoutSpecimen klass='.ns-split' note='two columns that share remaining space'>\r\n                <div class='ns-split'>\r\n                  <Plate>main</Plate>\r\n                  <Plate>aside</Plate>\r\n                </div>\r\n              </LayoutSpecimen>\r\n              <LayoutSpecimen klass='.ns-toolbar' note='action row with grouped ends'>\r\n                <div class='ns-toolbar'>\r\n                  <div class='ns-toolbar__group'>\r\n                    <Plate>filter</Plate>\r\n                    <Plate>sort</Plate>\r\n                  </div>\r\n                  <div class='ns-toolbar__group'>\r\n                    <Plate>export</Plate>\r\n                  </div>\r\n                </div>\r\n              </LayoutSpecimen>\r\n              <LayoutSpecimen\r\n                klass='.ns-switcher'\r\n                note='columns that stack below --ns-switcher-threshold'\r\n              >\r\n                <div class='ns-switcher'>\r\n                  <Plate>a</Plate>\r\n                  <Plate>b</Plate>\r\n                  <Plate>c</Plate>\r\n                </div>\r\n              </LayoutSpecimen>\r\n            </div>\r\n            <p class='ns-rules-footnote'>\r\n              Also in the vocabulary: <code>.ns-shell</code>, <code>.ns-section</code>,{' '}\r\n              <code>.ns-sidebar</code>, <code>.ns-content-rail</code>,{' '}\r\n              <code>.ns-scroll-region</code>, <code>.ns-cover</code>, <code>.ns-topbar</code>,{' '}\r\n              <code>.ns-status-bar</code>, and the <code>.ns-dashboard</code>{' '}\r\n              scaffold this page sits inside.\r\n            </p>\r\n          </section>\r\n\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='attributes'\r\n              title='Attribute contract'\r\n              lede='Interactive state is expressed with platform attributes, so styling and behavior stay decoupled.'\r\n            />\r\n            <dl class='ns-rules-defs'>\r\n              <div class='ns-rules-def'>\r\n                <dt>\r\n                  <code>data-part</code>\r\n                </dt>\r\n                <dd>Names the stable parts of a component — the seams CSS may target.</dd>\r\n              </div>\r\n              <div class='ns-rules-def'>\r\n                <dt>\r\n                  <code>data-state</code>\r\n                </dt>\r\n                <dd>Names visual state (open, checked, loading) without coupling to classes.</dd>\r\n              </div>\r\n              <div class='ns-rules-def'>\r\n                <dt>\r\n                  <code>aria-*</code>\r\n                </dt>\r\n                <dd>Describes accessibility state; it is the contract assistive tech reads.</dd>\r\n              </div>\r\n              <div class='ns-rules-def'>\r\n                <dt>prop getters</dt>\r\n                <dd>\r\n                  Event handlers, refs, and attribute bundles come from L1 runtime prop getters —\r\n                  components spread them, never reimplement them.\r\n                </dd>\r\n              </div>\r\n            </dl>\r\n            <p class='ns-rules-footnote'>\r\n              Native first: semantic elements, native form controls, and platform dialog / popover /\r\n              details behavior before any JavaScript state. Runtime code exists only for what the\r\n              platform does not provide.\r\n            </p>\r\n          </section>\r\n\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='rules'\r\n              title='Do / don’t'\r\n              lede='The ladder, the token rule, and the ownership line — as concrete habits.'\r\n            />\r\n            <div class='ns-rules-dodont'>\r\n              {DOS_AND_DONTS.map((pair) => (\r\n                <div key={pair.doText} class='ns-rules-dodont__pair'>\r\n                  <p class='ns-rules-do'>\r\n                    <span aria-hidden='true'>✓</span>\r\n                    {pair.doText}\r\n                  </p>\r\n                  <p class='ns-rules-dont'>\r\n                    <span aria-hidden='true'>✕</span>\r\n                    {pair.dontText}\r\n                  </p>\r\n                </div>\r\n              ))}\r\n            </div>\r\n          </section>\r\n        </div>\r\n      </div>\r\n    </main>\r\n  );\r\n}\r\n";
const template_020 =
  "import { appRoutes } from '@app/router.ts';\r\nimport { define } from '@app/utils.ts';\r\n\r\nexport const handler = define.handlers({\r\n  GET(ctx) {\r\n    return ctx.redirect(appRoutes.designTokens.href());\r\n  },\r\n});\r\n";
const template_021 =
  "import { Badge, Breadcrumb, SidebarShell } from '@app/components/ui/mod.ts';\r\nimport SidebarToggle from '@app/islands/ui/SidebarToggle.tsx';\r\nimport ThemeToggle from '@app/islands/ui/ThemeToggle.tsx';\r\nimport { appRoutes } from '@app/router.ts';\r\nimport { define } from '@app/utils.ts';\r\n\r\nconst DESIGN_NAVIGATION = [\r\n  {\r\n    label: 'Reference',\r\n    items: [\r\n      { href: appRoutes.designTokens.href(), label: 'Tokens', icon: '◧', matchPrefix: true },\r\n      {\r\n        href: appRoutes.designComponents.href(),\r\n        label: 'Components',\r\n        icon: '▣',\r\n        matchPrefix: true,\r\n      },\r\n      {\r\n        href: appRoutes.designComposition.href(),\r\n        label: 'Composition',\r\n        icon: '◰',\r\n        matchPrefix: true,\r\n      },\r\n    ],\r\n  },\r\n  {\r\n    label: 'App',\r\n    items: [\r\n      { href: appRoutes.home.href(), label: 'Home', icon: '◫', matchPrefix: false },\r\n    ],\r\n  },\r\n] as const;\r\n\r\nfunction buildDesignBreadcrumbs(pathname: string) {\r\n  const crumbs = [{ label: 'Design', href: '/design' }];\r\n  const section = pathname.replace(/^\\/design\\/?/, '').split('/')[0];\r\n  if (section) {\r\n    crumbs.push({\r\n      label: section.charAt(0).toUpperCase() + section.slice(1),\r\n      href: `/design/${section}`,\r\n    });\r\n  }\r\n  return crumbs.map((item, index) => index === crumbs.length - 1 ? { label: item.label } : item);\r\n}\r\n\r\nexport default define.layout(function DesignLayout({ Component, url }) {\r\n  return (\r\n    <SidebarShell\r\n      pathname={url.pathname}\r\n      navigation={DESIGN_NAVIGATION}\r\n      brand={\r\n        <a href='/' class='ns-topbar-brand'>\r\n          {{name}}\r\n        </a>\r\n      }\r\n      brandBadge={<Badge variant='secondary'>design system</Badge>}\r\n      topbarStart={\r\n        <>\r\n          <SidebarToggle />\r\n          <Breadcrumb items={buildDesignBreadcrumbs(url.pathname)} />\r\n        </>\r\n      }\r\n      topbarEnd={<ThemeToggle />}\r\n      footer={\r\n        <div class='ns-dashboard__sidebar-env'>\r\n          <span class='ns-dot-active' />\r\n          <span class='ns-dashboard__sidebar-env-label'>NS One theme</span>\r\n        </div>\r\n      }\r\n    >\r\n      <Component />\r\n    </SidebarShell>\r\n  );\r\n});\r\n";
const template_022 =
  "import DesignTokensView from './(_components)/tokens-view.tsx';\r\nimport { appRoutes } from '@app/router.ts';\r\nimport { definePage } from '@app/utils.ts';\r\n\r\nexport const designTokensPage = definePage()\r\n  .withRoute(appRoutes.designTokens)\r\n  .withMeta(() => ({\r\n    title: 'Design tokens — NetScript design system',\r\n    description: 'Token reference for the scaffolded @netscript/fresh-ui theme.',\r\n  }))\r\n  .withLayer('tokens', DesignTokensView, () => ({}))\r\n  .withLayout((slots) => slots.tokens())\r\n  .build();\r\n\r\nexport const { default: page } = designTokensPage;\r\nexport { page as default };\r\n";
const template_023 =
  "import type { VNode } from 'preact';\r\nimport { Badge } from '@app/components/ui/mod.ts';\r\nimport TokenClipboard from '../(_islands)/TokenClipboard.tsx';\r\nimport {\r\n  colorRamps,\r\n  type DesignToken,\r\n  easeTokens,\r\n  fontTokens,\r\n  foundationTokens,\r\n  leadingTokens,\r\n  radiusTokens,\r\n  type SemanticIntent,\r\n  semanticIntents,\r\n  shadowTokens,\r\n  spaceTokens,\r\n  textTokens,\r\n  tokenManifestMeta,\r\n  trackingTokens,\r\n  zTokens,\r\n} from '../(_shared)/tokens.ts';\r\n\r\nconst SECTIONS = [\r\n  { id: 'roles', label: 'Roles' },\r\n  { id: 'ramps', label: 'Ramps' },\r\n  { id: 'type', label: 'Type' },\r\n  { id: 'space', label: 'Space' },\r\n  { id: 'radius', label: 'Radius' },\r\n  { id: 'shadow', label: 'Shadow' },\r\n  { id: 'motion', label: 'Motion' },\r\n  { id: 'z', label: 'Z-scale' },\r\n] as const;\r\n\r\nconst SPECIMEN = 'Pack my box with five dozen liquor jugs';\r\n\r\n/** Copyable `var(--ns-*)` chip; TokenClipboard handles the click. */\r\nfunction CopyVar({ token }: { token: DesignToken }): VNode {\r\n  return (\r\n    <button\r\n      type='button'\r\n      class='ns-token-copy'\r\n      data-token-copy={`var(${token.cssVar})`}\r\n      title={`Copy var(${token.cssVar})`}\r\n    >\r\n      {token.cssVar}\r\n    </button>\r\n  );\r\n}\r\n\r\nfunction TokenRow(\r\n  { token, preview }: { token: DesignToken; preview: VNode },\r\n): VNode {\r\n  return (\r\n    <div class='ns-token-row'>\r\n      <div class='ns-token-row__preview'>{preview}</div>\r\n      <CopyVar token={token} />\r\n      <code class='ns-token-row__value'>{token.value}</code>\r\n    </div>\r\n  );\r\n}\r\n\r\nfunction SectionHeading(\r\n  { id, title, lede }: { id: string; title: string; lede: string },\r\n): VNode {\r\n  return (\r\n    <header class='ns-token-section__head'>\r\n      <h2 id={id} class='ns-token-section__title'>{title}</h2>\r\n      <p class='ns-token-section__lede'>{lede}</p>\r\n    </header>\r\n  );\r\n}\r\n\r\nfunction FoundationGrid(): VNode {\r\n  return (\r\n    <div class='ns-token-grid'>\r\n      {foundationTokens.map((token) => (\r\n        <TokenRow\r\n          key={token.name}\r\n          token={token}\r\n          preview={\r\n            <span\r\n              class='ns-token-swatch'\r\n              style={`background: var(${token.cssVar});`}\r\n            />\r\n          }\r\n        />\r\n      ))}\r\n    </div>\r\n  );\r\n}\r\n\r\nfunction IntentStrip({ intent }: { intent: SemanticIntent }): VNode | null {\r\n  const base = intent.tokens.find((token) => token.name === intent.role);\r\n  const fg = intent.tokens.find((token) => token.name === `${intent.role}-fg`);\r\n  const rest = intent.tokens.filter((token) => token !== base && token !== fg);\r\n  if (!base || !fg) return null;\r\n  return (\r\n    <div class='ns-token-intent'>\r\n      <button\r\n        type='button'\r\n        class='ns-token-intent__hero'\r\n        style={`background: var(${base.cssVar}); color: var(${fg.cssVar});`}\r\n        data-token-copy={`var(${base.cssVar})`}\r\n        title={`Copy var(${base.cssVar})`}\r\n      >\r\n        <strong>{intent.role}</strong>\r\n        <code>{base.cssVar}</code>\r\n      </button>\r\n      <div class='ns-token-intent__companions'>\r\n        {[fg, ...rest].map((token) => (\r\n          <TokenRow\r\n            key={token.name}\r\n            token={token}\r\n            preview={\r\n              <span\r\n                class='ns-token-swatch ns-token-swatch--sm'\r\n                style={`background: var(${token.cssVar});`}\r\n              />\r\n            }\r\n          />\r\n        ))}\r\n      </div>\r\n    </div>\r\n  );\r\n}\r\n\r\nfunction RampStrips(): VNode {\r\n  return (\r\n    <div class='ns-stack ns-stack--lg'>\r\n      {colorRamps.map((ramp) => (\r\n        <figure key={ramp.name} class='ns-token-ramp'>\r\n          <figcaption class='ns-token-ramp__name'>\r\n            {ramp.name}\r\n            <span class='ns-token-ramp__range'>\r\n              {ramp.steps[0]?.name.split('-').pop()}–{ramp.steps.at(-1)?.name.split('-').pop()}\r\n            </span>\r\n          </figcaption>\r\n          <div class='ns-token-ramp__strip'>\r\n            {ramp.steps.map((step) => (\r\n              <button\r\n                key={step.name}\r\n                type='button'\r\n                class='ns-token-ramp__step'\r\n                style={`background: var(${step.cssVar});`}\r\n                data-token-copy={`var(${step.cssVar})`}\r\n                title={`${step.cssVar} · ${step.value}`}\r\n              >\r\n                <span class='ns-token-ramp__step-label'>{step.name.split('-').pop()}</span>\r\n              </button>\r\n            ))}\r\n          </div>\r\n        </figure>\r\n      ))}\r\n    </div>\r\n  );\r\n}\r\n\r\nfunction TypeSpecimens(): VNode {\r\n  return (\r\n    <div class='ns-stack ns-stack--lg'>\r\n      {fontTokens.map((token) => (\r\n        <TokenRow\r\n          key={token.name}\r\n          token={token}\r\n          preview={\r\n            <span\r\n              class='ns-token-type-specimen'\r\n              style={`font-family: var(${token.cssVar});`}\r\n            >\r\n              {SPECIMEN}\r\n            </span>\r\n          }\r\n        />\r\n      ))}\r\n      {textTokens.map((token) => (\r\n        <TokenRow\r\n          key={token.name}\r\n          token={token}\r\n          preview={\r\n            <span\r\n              class='ns-token-type-specimen'\r\n              style={`font-size: var(${token.cssVar});`}\r\n            >\r\n              Scale {token.name.replace('text-', '')}\r\n            </span>\r\n          }\r\n        />\r\n      ))}\r\n      {leadingTokens.map((token) => (\r\n        <TokenRow\r\n          key={token.name}\r\n          token={token}\r\n          preview={\r\n            <span\r\n              class='ns-token-type-paragraph'\r\n              style={`line-height: var(${token.cssVar});`}\r\n            >\r\n              {SPECIMEN}, then wraps onto a second line to show its leading.\r\n            </span>\r\n          }\r\n        />\r\n      ))}\r\n      {trackingTokens.map((token) => (\r\n        <TokenRow\r\n          key={token.name}\r\n          token={token}\r\n          preview={\r\n            <span\r\n              class='ns-token-type-specimen'\r\n              style={`letter-spacing: var(${token.cssVar});`}\r\n            >\r\n              tracking\r\n            </span>\r\n          }\r\n        />\r\n      ))}\r\n    </div>\r\n  );\r\n}\r\n\r\nfunction SpaceBars(): VNode {\r\n  return (\r\n    <div class='ns-token-grid'>\r\n      {spaceTokens.map((token) => (\r\n        <TokenRow\r\n          key={token.name}\r\n          token={token}\r\n          preview={\r\n            <span class='ns-token-space-track'>\r\n              <span\r\n                class='ns-token-space-bar'\r\n                style={`width: var(${token.cssVar});`}\r\n              />\r\n            </span>\r\n          }\r\n        />\r\n      ))}\r\n    </div>\r\n  );\r\n}\r\n\r\nfunction RadiusTiles(): VNode {\r\n  return (\r\n    <div class='ns-token-tiles'>\r\n      {radiusTokens.map((token) => (\r\n        <TokenRow\r\n          key={token.name}\r\n          token={token}\r\n          preview={\r\n            <span\r\n              class='ns-token-radius-tile'\r\n              style={`border-radius: var(${token.cssVar});`}\r\n            />\r\n          }\r\n        />\r\n      ))}\r\n    </div>\r\n  );\r\n}\r\n\r\nfunction ShadowTiles(): VNode {\r\n  return (\r\n    <div class='ns-token-tiles'>\r\n      {shadowTokens.map((token) => (\r\n        <TokenRow\r\n          key={token.name}\r\n          token={token}\r\n          preview={\r\n            <span\r\n              class='ns-token-shadow-tile'\r\n              style={`box-shadow: var(${token.cssVar});`}\r\n            />\r\n          }\r\n        />\r\n      ))}\r\n    </div>\r\n  );\r\n}\r\n\r\nfunction MotionChips(): VNode {\r\n  return (\r\n    <div class='ns-token-tiles'>\r\n      {easeTokens.map((token) => (\r\n        <TokenRow\r\n          key={token.name}\r\n          token={token}\r\n          preview={\r\n            <span\r\n              class='ns-token-motion-chip'\r\n              style={`transition: transform var(${token.cssVar});`}\r\n            >\r\n              hover\r\n            </span>\r\n          }\r\n        />\r\n      ))}\r\n    </div>\r\n  );\r\n}\r\n\r\nfunction ZStack(): VNode {\r\n  return (\r\n    <div class='ns-token-zstack'>\r\n      {zTokens.map((token, index) => (\r\n        <button\r\n          key={token.name}\r\n          type='button'\r\n          class='ns-token-zplate'\r\n          style={`z-index: var(${token.cssVar}); --zplate-indent: ${index * 2.5}rem;`}\r\n          data-token-copy={`var(${token.cssVar})`}\r\n          title={`Copy var(${token.cssVar})`}\r\n        >\r\n          <code>{token.cssVar}</code>\r\n          <span>{token.value}</span>\r\n        </button>\r\n      ))}\r\n    </div>\r\n  );\r\n}\r\n\r\nexport default function DesignTokensView() {\r\n  return (\r\n    <main class='ns-tokens-page'>\r\n      <TokenClipboard />\r\n\r\n      <header class='ns-page-header'>\r\n        <div class='ns-cluster ns-cluster--md'>\r\n          <h1>Tokens</h1>\r\n          <Badge variant='primary'>NS One</Badge>\r\n          <Badge variant='muted'>manifest v{tokenManifestMeta.version}</Badge>\r\n        </div>\r\n        <p class='ns-lede'>\r\n          The{' '}\r\n          {tokenManifestMeta.total}-token vocabulary every component is allowed to speak. Swatches\r\n          render from the live CSS variables, so this page always shows the active theme. Click any\r\n          token to copy its variable.\r\n        </p>\r\n      </header>\r\n\r\n      <div class='ns-tokens-layout'>\r\n        <nav class='ns-tokens-rail' aria-label='Token sections'>\r\n          {SECTIONS.map((section) => (\r\n            <a key={section.id} href={`#${section.id}`} class='ns-tokens-rail__link'>\r\n              {section.label}\r\n            </a>\r\n          ))}\r\n        </nav>\r\n\r\n        <div class='ns-tokens-sections'>\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='roles'\r\n              title='Semantic roles'\r\n              lede='What components consume. Surfaces, text, and borders first; the six intents below each pair a base with its fg, hover, subtle, and border companions.'\r\n            />\r\n            <FoundationGrid />\r\n            <div class='ns-stack ns-stack--lg'>\r\n              {semanticIntents.map((intent) => <IntentStrip key={intent.role} intent={intent} />)}\r\n            </div>\r\n          </section>\r\n\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='ramps'\r\n              title='Primitive ramps'\r\n              lede='Theme raw material. Semantic roles map onto these steps; components never reference a ramp directly.'\r\n            />\r\n            <RampStrips />\r\n          </section>\r\n\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='type'\r\n              title='Type'\r\n              lede='Families, scale, leading, and tracking — each rendered at its own value.'\r\n            />\r\n            <TypeSpecimens />\r\n          </section>\r\n\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='space'\r\n              title='Space'\r\n              lede='The spacing scale, drawn to size.'\r\n            />\r\n            <SpaceBars />\r\n          </section>\r\n\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='radius'\r\n              title='Radius'\r\n              lede='Corner rounding, from subtle to full pill.'\r\n            />\r\n            <RadiusTiles />\r\n          </section>\r\n\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='shadow'\r\n              title='Shadow'\r\n              lede='Elevation steps for raised surfaces and overlays.'\r\n            />\r\n            <ShadowTiles />\r\n          </section>\r\n\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='motion'\r\n              title='Motion'\r\n              lede='Duration and easing pairs. Hover a chip to feel each curve.'\r\n            />\r\n            <MotionChips />\r\n          </section>\r\n\r\n          <section class='ns-token-section'>\r\n            <SectionHeading\r\n              id='z'\r\n              title='Z-scale'\r\n              lede='The stacking order contract: each layer sits exactly one plate above the last.'\r\n            />\r\n            <ZStack />\r\n          </section>\r\n        </div>\r\n      </div>\r\n    </main>\r\n  );\r\n}\r\n";
