const template_042 =
  "import { getServiceUrl } from '@netscript/sdk';\r\n\r\n// ---------------------------------------------------------------------------\r\n// Types\r\n// ---------------------------------------------------------------------------\r\n\r\nexport interface TelemetrySpan {\r\n  readonly traceId: string;\r\n  readonly spanId: string;\r\n  readonly parentSpanId: string;\r\n  readonly name: string;\r\n  readonly service: string;\r\n  readonly kind: number;\r\n  readonly durationMs: number;\r\n}\r\n\r\nexport interface TelemetryTrace {\r\n  readonly traceId: string;\r\n  readonly services: readonly string[];\r\n  readonly spans: readonly TelemetrySpan[];\r\n  readonly isCrossService: boolean;\r\n}\r\n\r\nexport interface TelemetryTraceData {\r\n  readonly traces: readonly TelemetryTrace[];\r\n  readonly totalSpans: number;\r\n  readonly dashboardUrl: string;\r\n  readonly error?: string;\r\n}\r\n\r\nexport interface WebhookFireResult {\r\n  readonly ok: boolean;\r\n  readonly status?: number;\r\n  readonly error?: string;\r\n}\r\n\r\n// ---------------------------------------------------------------------------\r\n// Dashboard API helpers\r\n// ---------------------------------------------------------------------------\r\n\r\ninterface OtlpSpan {\r\n  name: string;\r\n  kind: number;\r\n  traceId: string;\r\n  spanId: string;\r\n  parentSpanId: string;\r\n  startTimeUnixNano: string;\r\n  endTimeUnixNano: string;\r\n}\r\n\r\ninterface OtlpScopeSpans {\r\n  spans: OtlpSpan[];\r\n}\r\n\r\ninterface OtlpResource {\r\n  attributes: { key: string; value: { stringValue?: string } }[];\r\n}\r\n\r\ninterface OtlpResourceSpans {\r\n  scopeSpans: OtlpScopeSpans[];\r\n  resource: OtlpResource;\r\n}\r\n\r\ninterface DashboardTraceResponse {\r\n  data: { resourceSpans: OtlpResourceSpans[] };\r\n  totalCount: number;\r\n}\r\n\r\nfunction getDashboardBaseUrl(): string {\r\n  const port = Deno.env.get('ASPIRE_DASHBOARD_PORT') ?? '18888';\r\n  return `https://localhost:${port}`;\r\n}\r\n\r\nfunction getServiceName(resource: OtlpResource): string {\r\n  return (\r\n    resource.attributes.find((a) => a.key === 'service.name')?.value\r\n      .stringValue ?? 'unknown'\r\n  );\r\n}\r\n\r\nfunction nanoDuration(start: string, end: string): number {\r\n  return Math.round((Number(BigInt(end) - BigInt(start)) / 1_000_000));\r\n}\r\n\r\nexport async function fetchDashboardTraces(): Promise<TelemetryTraceData> {\r\n  const baseUrl = getDashboardBaseUrl();\r\n  const url = `${baseUrl}/api/telemetry/traces`;\r\n\r\n  try {\r\n    const resp = await fetch(url, {\r\n      headers: { Accept: 'application/json' },\r\n    });\r\n    if (!resp.ok) {\r\n      return { traces: [], totalSpans: 0, dashboardUrl: baseUrl, error: `Dashboard API ${resp.status}` };\r\n    }\r\n\r\n    const body = (await resp.json()) as DashboardTraceResponse;\r\n    const rs = body.data.resourceSpans;\r\n\r\n    const allSpans: TelemetrySpan[] = [];\r\n    for (const r of rs) {\r\n      const svc = getServiceName(r.resource);\r\n      for (const ss of r.scopeSpans) {\r\n        for (const span of ss.spans) {\r\n          allSpans.push({\r\n            traceId: span.traceId,\r\n            spanId: span.spanId,\r\n            parentSpanId: span.parentSpanId,\r\n            name: span.name,\r\n            service: svc,\r\n            kind: span.kind,\r\n            durationMs: nanoDuration(span.startTimeUnixNano, span.endTimeUnixNano),\r\n          });\r\n        }\r\n      }\r\n    }\r\n\r\n    const byTrace = new Map<string, TelemetrySpan[]>();\r\n    for (const s of allSpans) {\r\n      const arr = byTrace.get(s.traceId) ?? [];\r\n      arr.push(s);\r\n      byTrace.set(s.traceId, arr);\r\n    }\r\n\r\n    const traces: TelemetryTrace[] = [...byTrace.entries()]\r\n      .map(([traceId, spans]) => {\r\n        const services = [...new Set(spans.map((s) => s.service))];\r\n        return {\r\n          traceId,\r\n          services,\r\n          spans,\r\n          isCrossService: services.length > 1,\r\n        };\r\n      })\r\n      .sort((a, b) => b.spans.length - a.spans.length)\r\n      .slice(0, 20);\r\n\r\n    return { traces, totalSpans: allSpans.length, dashboardUrl: baseUrl };\r\n  } catch (err) {\r\n    const msg = err instanceof Error ? err.message : String(err);\r\n    return { traces: [], totalSpans: 0, dashboardUrl: baseUrl, error: msg };\r\n  }\r\n}\r\n\r\n// ---------------------------------------------------------------------------\r\n// Webhook trigger\r\n// ---------------------------------------------------------------------------\r\n\r\nexport async function fireWebhookTrace(): Promise<WebhookFireResult> {\r\n  try {\r\n    const triggersUrl = getServiceUrl('triggers-api', 'http');\r\n    const webhookUrl = `${triggersUrl}/api/v1/webhooks/inbound/generic`;\r\n    const resp = await fetch(webhookUrl, {\r\n      method: 'POST',\r\n      headers: { 'Content-Type': 'application/json' },\r\n      body: JSON.stringify({\r\n        message: 'telemetry-page-trace',\r\n        timestamp: new Date().toISOString(),\r\n      }),\r\n    });\r\n    return { ok: resp.ok, status: resp.status };\r\n  } catch (err) {\r\n    return { ok: false, error: err instanceof Error ? err.message : String(err) };\r\n  }\r\n}\r\n";
