const template_093 =
  "/**\r\n * {{serviceName | pascalCase}} router — Prisma-backed CRUD handlers for v1.\r\n */\r\n\r\nimport type { PrismaClient } from '@database';\r\nimport { v1 } from '@{{projectName}}/contracts';\r\n\r\ntype {{modelName}}Delegate = PrismaClient['{{modelName | camelCase}}'];\r\ntype {{modelName}}FindManyArgs = NonNullable<Parameters<{{modelName}}Delegate['findMany']>[0]>;\r\ntype {{modelName}}HandlerContext = { readonly db: PrismaClient };\r\n\r\nconst SORTABLE_FIELDS = new Set(['id', 'name', 'createdAt', 'updatedAt']);\r\nconst {{serviceName | camelCase}}V1 = v1.{{serviceName | camelCase}}.$context<{{modelName}}HandlerContext>();\r\n\r\nfunction {{modelName | camelCase}}Delegate(context: {{modelName}}HandlerContext): {{modelName}}Delegate {\r\n  return context.db.{{modelName | camelCase}};\r\n}\r\n\r\nfunction orderBy(input: { readonly sortBy?: string; readonly sortOrder: 'asc' | 'desc' }) {\r\n  const field = input.sortBy && SORTABLE_FIELDS.has(input.sortBy) ? input.sortBy : 'id';\r\n  return { [field]: input.sortOrder };\r\n}\r\n\r\nexport const {{serviceName | pascalCase}}V1 = {\r\n  list: {{serviceName | camelCase}}V1.list.handler(async ({ input, context }) => {\r\n    const delegate = {{modelName | camelCase}}Delegate(context);\r\n    const page = input.page;\r\n    const limit = input.limit;\r\n    const skip = (page - 1) * limit;\r\n    const findManyArgs = {\r\n      skip,\r\n      take: limit,\r\n      orderBy: orderBy(input),\r\n    } satisfies {{modelName}}FindManyArgs;\r\n\r\n    const [data, total] = await Promise.all([\r\n      delegate.findMany(findManyArgs),\r\n      delegate.count(),\r\n    ]);\r\n    const totalPages = Math.ceil(total / limit);\r\n\r\n    return {\r\n      data,\r\n      pagination: {\r\n        page,\r\n        limit,\r\n        total,\r\n        totalPages,\r\n        hasNext: page < totalPages,\r\n        hasPrev: page > 1,\r\n      },\r\n    };\r\n  }),\r\n  getById: {{serviceName | camelCase}}V1.getById.handler(async ({ input, context }) => {\r\n    const record = await {{modelName | camelCase}}Delegate(context).findUnique({\r\n      where: { id: input.id },\r\n    });\r\n    if (!record) {\r\n      throw new Error(`{{modelName}} ${input.id} not found`);\r\n    }\r\n    return record;\r\n  }),\r\n  create: {{serviceName | camelCase}}V1.create.handler(async ({ input, context }) =>\r\n    await {{modelName | camelCase}}Delegate(context).create({ data: input })\r\n  ),\r\n  update: {{serviceName | camelCase}}V1.update.handler(async ({ input, context }) =>\r\n    await {{modelName | camelCase}}Delegate(context).update({\r\n      where: { id: input.id },\r\n      data: input.data,\r\n    })\r\n  ),\r\n  delete: {{serviceName | camelCase}}V1.delete.handler(async ({ input, context }) =>\r\n    await {{modelName | camelCase}}Delegate(context).delete({\r\n      where: { id: input.id },\r\n    })\r\n  ),\r\n};\r\n";
const template_094 =
  "/**\r\n * {{serviceName | pascalCase}} router — seeded example handlers for v1.\r\n *\r\n * Step 5 intentionally returns stable in-memory records so the generated\r\n * frontend can prove the FE → service contract when no database is scaffolded.\r\n */\r\n\r\nimport { v1, type {{serviceName | pascalCase}}ListItemV1 } from '@{{projectName}}/contracts';\r\n\r\nconst NEXT_STATUS_BY_STATE: Record<\r\n  {{serviceName | pascalCase}}ListItemV1['status'],\r\n  {{serviceName | pascalCase}}ListItemV1['status']\r\n> = {\r\n  draft: 'active',\r\n  active: 'archived',\r\n  archived: 'draft',\r\n};\r\n\r\nlet seededRecords: {{serviceName | pascalCase}}ListItemV1[] = [\r\n  {\r\n    id: 1,\r\n    name: 'Launch checklist',\r\n    summary: 'Tracks the first release milestones for the scaffolded service.',\r\n    status: 'active',\r\n    createdAt: '2026-04-21T08:00:00.000Z',\r\n  },\r\n  {\r\n    id: 2,\r\n    name: 'Integration handshake',\r\n    summary: 'Verifies the frontend route can hydrate from the generated service.',\r\n    status: 'draft',\r\n    createdAt: '2026-04-20T12:30:00.000Z',\r\n  },\r\n  {\r\n    id: 3,\r\n    name: 'Telemetry follow-up',\r\n    summary: 'Reserved for the later rollout step that wires end-to-end tracing.',\r\n    status: 'archived',\r\n    createdAt: '2026-04-19T15:45:00.000Z',\r\n  },\r\n];\r\n\r\nexport const {{serviceName | pascalCase}}V1 = {\r\n  list: v1.{{serviceName | camelCase}}.list.handler(async ({ input }) => {\r\n    const search = input.search?.trim().toLowerCase();\r\n    const filtered = search\r\n      ? seededRecords.filter((record) =>\r\n        record.name.toLowerCase().includes(search)\r\n      )\r\n      : [...seededRecords];\r\n    const items = filtered.slice(input.offset, input.offset + input.limit);\r\n\r\n    return {\r\n      items,\r\n      total: filtered.length,\r\n      limit: input.limit,\r\n      offset: input.offset,\r\n      hasMore: input.offset + input.limit < filtered.length,\r\n    };\r\n  }),\r\n  updateStatus: v1.{{serviceName | camelCase}}.updateStatus.handler(async ({ input }) => {\r\n    const record = seededRecords.find((entry) => entry.id === input.id);\r\n\r\n    if (!record) {\r\n      throw new Error(`{{serviceName}} record ${input.id} not found`);\r\n    }\r\n\r\n    const nextStatus = input.status;\r\n    record.status = nextStatus;\r\n    record.summary = nextStatus === 'archived'\r\n      ? 'Archived after the optimistic showcase mutation completed.'\r\n      : nextStatus === 'active'\r\n      ? 'Re-activated through the scaffolded optimistic update flow.'\r\n      : 'Moved back into draft to demonstrate typed mutation rollbacks.';\r\n\r\n    return {\r\n      ...record,\r\n    };\r\n  }),\r\n};\r\n";
